    // Calcular el nombre esperado del token
    let expected_token_name =
      first_input.output_reference
        |> cbor.serialise
        |> blake2b_256

    // El nombre del activo debe coincidir con el hash y la cantidad debe ser 1
    asset_name == expected_token_name && quantity == 1
  }

  // Rechazar cualquier otro propósito de script
  else(_) {
    fail
  }
}
