Use `assets.tokens` to get the asset map for your policy, then `list.length` on its flattened representation, or use `assets.flatten` and `list.count`:

```aiken
use aiken/collection/list
use cardano/assets.{PolicyId, flatten, quantity_of}
use cardano/transaction.{Transaction}

validator single_mint {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    // Count all token entries under this policy in the mint field
    let minted_tokens =
      flatten(self.mint)
        |> list.filter(fn(entry) {
             let (pid, _name, _qty) = entry
             pid == policy_id
           })
    // Exactly one asset name minted, quantity == 1
    when minted_tokens is {
      [(_, _, qty)] -> qty == 1
      _ -> False
    }
  }
}
