    let minted_tokens = assets.tokens(self.mint, policy_id)
    let has_minted = !dict.is_empty(minted_tokens)
    let signed = list.has(self.extra_signatories, owner)
    has_minted && signed
  }

  else(_) {
    fail
  }
}
```

