}
```

`self.mint` is a `Value` representing all tokens minted (positive) or burned (negative) in this transaction. `assets.quantity_of/3` looks up the quantity for the specific `(policy_id, asset_name)` pair. The validator approves only when exactly 1 token of the asset named by the redeemer is minted under this policy.

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval
use cardano/transaction.{Transaction, OutputReference}

validator time_lock_or_owner(owner_key: VerificationKeyHash, deadline: Int) {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let signed_by_owner = list.has(self.extra_signatories, owner_key)
    let before_deadline = interval.is_entirely_before(self.validity_range, deadline)
    signed_by_owner || before_deadline
  }
}
```

`||` short-circuits: if `signed_by_owner` is `True`, `before_deadline` is never evaluated, saving on-chain execution budget.

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

validator single_mint(authorized_key: VerificationKeyHash, policy_asset_name: AssetName) {
  mint(
    _redeemer: Void,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let signed = list.has(self.extra_signatories, authorized_key)
    let minted_qty =
      assets.quantity_of(self.mint, policy_id, policy_asset_name)
    signed && minted_qty == 1
  }
}
```

Because `&&` short-circuits, if `signed` is `False` the quantity check is skipped entirely, saving execution budget.

In Aiken, boolean negation uses the `!` operator, which flips `True` to `False` and vice versa.

Here is a spend validator that rejects the transaction if a blocked key has signed it:

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/transaction.{Transaction, OutputReference}

validator blocklist(blocked_key: VerificationKeyHash) {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let blocked_signed = list.has(self.extra_signatories, blocked_key)
    !blocked_signed
  }
}
```

`!blocked_signed` evaluates to `True` only when the blocked key is **not** among the transaction's signatories, allowing the spend to proceed.

