use aiken/crypto.{VerificationKeyHash}
use cardano/transaction.{OutputReference, Transaction}

validator my_validator {
  spend(datum: Option<Int>, redeemer: Int, own_ref: OutputReference, self: Transaction) -> Bool {
    let signed_by_alice = list.has(self.extra_signatories, #"abcd")
    let signed_by_bob = list.has(self.extra_signatories, #"ef01")
