    redeemer == expected
  }
}
```

This validator compares the redeemer (a `ByteArray` expressed using hex notation) against the hardcoded value `#"deadbeef"`. Equality on `ByteArray` is structural, so every byte must match.

```aiken
use cardano/transaction.{OutputReference, Transaction}

validator non_empty_redeemer {
  spend(
    _datum: Option<Data>,
    redeemer: ByteArray,
    _own_ref: OutputReference,
    _self: Transaction,
