The `// ## Constructing` heading groups the factory functions, while `// ## Inspecting` groups the query functions. This matches the conventional pattern used in the Aiken standard library itself (e.g., `aiken/option` uses `// ## Inspecting`).

```aiken
use aiken/interval
use cardano/transaction.{Transaction}
use cardano/assets.{Lovelace}

// ## Helpers

fn after_deadline(self: Transaction, deadline: Int) -> Bool {
  interval.is_entirely_after(self.validity_range, deadline)
}

// ## Validator

validator timelocked_withdraw(deadline: Int) {
  withdraw(redeemer: Void, _account: Credential, self: Transaction) -> Bool {
    after_deadline(self, deadline)
  }

  else(_) {
    fail
  }
}
```

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/transaction.{Transaction, OutputReference}

pub type Datum {
  allowed_keys: List<VerificationKeyHash>,
}

validator allowlist {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) ->
        list.all(
          self.extra_signatories,
          fn(signer) { list.has(d.allowed_keys, signer) },
        )
      None -> False
    }
  }
}
